prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?label ?orgId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(STR(?orgId) = "4d36ddb24c9e4cc38572abbd646c1e58")
  OPTIONAL { ?org rdfs:label ?label . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT 
  ?org ?orgLabel
  (COUNT(DISTINCT ?model) AS ?modelCount)
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (SUM(?taskCount) AS ?totalTaskCount)
  (SUM(?participantCount) AS ?totalParticipantCount)
  (SUM(?messageFlowCount) AS ?totalMessageFlowCount)
  (SUM(?gatewayCount) AS ?totalGatewayCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  OPTIONAL { ?org rdfs:label ?orgLabel . }

  ?model a bboExt:Model ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  { SELECT ?choreo
           (COUNT(DISTINCT ?task) AS ?taskCount)
           (COUNT(DISTINCT ?participant) AS ?participantCount)
           (COUNT(DISTINCT ?msg) AS ?messageFlowCount)
           (COUNT(DISTINCT ?gw) AS ?gatewayCount)
    WHERE {
      OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
      OPTIONAL { ?participant a bboExt:Participant ; tai:belongsTo ?choreo . }
      OPTIONAL { ?msg a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
      OPTIONAL {
        ?gw a ?gwType ; tai:belongsTo ?choreo .
        FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
      }
    }
    GROUP BY ?choreo
  }
}
GROUP BY ?org ?orgLabel

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?choreo ?choreoName WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo <https://www.teamingai-project.eu/kg/organization/Org25> ;
         bbo:name ?modelName .

  OPTIONAL {
    ?choreo a bboExt:Choreography ;
            tai:belongsTo ?model .
    OPTIONAL { ?choreo bbo:name ?choreoName . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?modelName WHERE {
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?defs tai:belongsTo ?model . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  FILTER( EXISTS {
    ?model tai:belongsTo <https://www.teamingai-project.eu/kg/organization/Org25> .
  })
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT 
  ?org ?orgLabel
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
  (COUNT(DISTINCT ?msgFlow) AS ?messageFlowCount)
  (COUNT(DISTINCT ?xorGw) AS ?exclusiveGatewayCount)
  (COUNT(DISTINCT ?andGw) AS ?parallelGatewayCount)
  (COUNT(DISTINCT ?evGw) AS ?eventBasedGatewayCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  OPTIONAL { ?org rdfs:label ?orgLabel . }

  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:belongsTo ?org .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?participant a bboExt:Participant ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }

  OPTIONAL { ?xorGw a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?andGw a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?evGw a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
}
GROUP BY ?org ?orgLabel
LIMIT 25
